int change_name()
{
  puts("Your new name:");
  read(0, &name, 0x20u);
  return puts("Done!");
}

void *change_message()
{
  void *result; // rax
  int v1; // [rsp+4h] [rbp-Ch]
  void *buf; // [rsp+8h] [rbp-8h]

  puts("So I think the old message is useless,right?");
  printf("Your message is saved at %p\n", message);
  free(message);
  puts("Your size of new message:");
  v1 = read_int();
  if ( v1 <= 127 || v1 > 239 )
  {
    puts("Error size!");
    exit(0);
  }
  buf = malloc(v1);
  puts("Input your new message:");
  read(0, buf, v1);
  puts("Done!");
  puts("Oh,I'm sorry,maybe you should say goodbye to the old message:");
  read(0, message, 0x10u);
  puts("New!");
  result = buf;
  message = buf;
  return result;
}

int __fastcall __noreturn main(int argc, const char **argv, const char **envp)
{
  int v3; // [rsp+8h] [rbp-8h]
  int v4; // [rsp+Ch] [rbp-4h]

  init();
  init_name_message();
  v3 = 0;
  while ( 1 )
  {
    while ( 1 )
    {
      menu();
      v4 = read_int();
      if ( v4 != 1 )
        break;
      add();
    }
    switch ( v4 )
    {
      case 2:
        edit();
        break;
      case 3:
        delete();
        break;
      case 4:
        change_name();
        break;
      case 5:
        if ( v3 )
        {
          puts("I think one chance is enough");
        }
        else
        {
          change_message();
          v3 = 1;
        }
        break;
      case 6:
        puts("Good job!");
        exit(0);
      default:
        puts("Invalid choice!");
        break;
    }
  }
}

